import { Registry } from "../../core/zc-registry";

const geoLocation3 = (size) => {
    return {
        outer:
            `${'M' + ' '}${size * -0.3654} ${size * -0.928}L` +
            ` ${size * -0.3654} ${size * -0.3712}C` +
            ` ${size * -0.319} ${size * -0.1392} ${size * -0.1334} ${size * -0.0928} ${size * 0.0058} ${0}C` +
            ` ${size * 0.145} ${size * -0.0928} ${size * 0.3306} ${size * -0.1392} ${size * 0.377} ${size * -0.3712}L` +
            ` ${size * 0.377} ${size * -0.928}C` +
            ` ${size * 0.0522} ${size * -1.0208} ${size * -0.0406} ${size * -1.0208} ${size * -0.3654} ${size * -0.928}Z`,
        inner:
            `${'M' + ' '}${size * -0.5452} ${size * -1.392}L` +
            ` ${size * -0.174} ${size * -1.392}L` +
            ` ${size * 0.0116} ${size * -1.7632}L` +
            ` ${size * 0.1972} ${size * -1.392}L` +
            ` ${size * 0.5684} ${size * -1.392}L` +
            ` ${size * 0.29} ${size * -1.1136}L` +
            ` ${size * 0.4756} ${size * -0.6496}L` +
            ` ${size * 0.0116} ${size * -0.928}L` +
            ` ${size * -0.4524} ${size * -0.6496}L` +
            ` ${size * -0.2668} ${size * -1.1136}`
    }
};
Registry.getComponent('svg.symbols.constants')['geo-location-3'] = geoLocation3;
export default geoLocation3;